  ('aboriginal-0a2fc18c-moex-00123', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-112-6ed013db', 'sub-aboriginal-0a2fc18c-07', NULL, 'single_choice', '主管機關為審議各類原住民族文化資產所涉文化資產保存法規定之重大事項，應設原住民族文化資產審議 會，專責審議原住民族文化資產；此一審議會的人員組成，依原住民族文化資產處理辦法規定，應有多少 比例以上為非機關人員？', '["二分之一", "三分之一", "三分之二", "四分之三"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "509", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
